def is_moe_from_config(config) -> bool:
    """Config-only MoE detection — does NOT instantiate the model.

    Use this whenever we need to decide MoE handling BEFORE the model is loaded
    (e.g. arch detection from a 45GB bf16 Mistral that would OOM a 32GB GPU on
    eager `from_pretrained`). For known MoE model_types and configs exposing
    `num_experts` / `num_local_experts`, this is sufficient. Custom-code MoE
    architectures not in MOE_TYPES would need a follow-up walk after load.
    """
    if hasattr(config, "num_experts") or hasattr(config, "num_local_experts"):
        return True
    model_type = getattr(config, "model_type", "")
    if model_type in MOE_TYPES:
        return True
    return False
